import numpy as np

def predict(frame, action):
    if action == 6:
        new_frame = frame.copy()
        for col in range(63, -1, -2):
            if col >= 31 and (col != 30 or frame[0, 30] != 4) and (col != 31 or frame[0, 31] != 4):
                new_frame[0, col] = 4
            if col - 1 >= 31 and (col - 1 != 30 or frame[0, 30] != 4) and (col - 1 != 31 or frame[0, 31] != 4):
                new_frame[0, col - 1] = 4
        return new_frame
    return frame
